task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        if M.isSharedStallActive() then
            local remaining = math.max(0, math.ceil(M.getSharedStallUntil() - tick()))
            statusLabel:SetText("Status: Stalled " .. remaining .. "s ")
        elseif M.isClaimingWins() then
            statusLabel:SetText("Status: Claiming Wins ")
        elseif M.isListening() then
            statusLabel:SetText("Status: Listening... ")
        elseif M.isAllCaptured() then
            statusLabel:SetText("Status: Ready! ")
        else
            statusLabel:SetText("Status: Not set up yet ")
        end
        worldLabel:SetText("Tower: " .. (M.getCurrentWorldName() or "not found") .. " ")
    end
end)

