-- FARM POSITION TAB
local SpotLeft  = Tabs.Spot:AddLeftGroupbox("Position Override ")
local SpotRight = Tabs.Spot:AddRightGroupbox("Quick-Save Key ")

local overrideLabel = SpotLeft:AddLabel({ Text = "Custom Position: OFF " })
local savedCFLabel  = SpotLeft:AddLabel({ Text = "Saved: none " })

SpotLeft:AddButton("Save Current Position ", function()
    local char = game.Players.LocalPlayer.Character
    if not char then Library:Notify({Title="Error ", Description="No character! ", Duration=3}) return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then Library:Notify({Title="Error ", Description="No HumanoidRootPart! ", Duration=3}) return end
    M.setCustomCFrameOverride(root.CFrame)
    local p = root.Position
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
    Library:Notify({Title="Position Saved! ", Description=string.format("%.1f, %.1f, %.1f", p.X, p.Y, p.Z), Duration=4})
end)

SpotLeft:AddButton("Clear Custom Position ", function()
    M.setCustomCFrameOverride(nil)
    savedCFLabel:SetText("Saved: none ")
    Library:Notify({Title="Cleared ", Description="Using original captured spot. ", Duration=3})
end)

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        overrideLabel:SetText("Custom Position: " .. (M.getCustomCFrameOverride() and "ON " or "OFF "))
    end
end)

